// BrightPath Spanish, beginner-friendly progression through conversational fluency
// Spanish levels map loosely to grades but follow a "years of study" ladder,
// so a beginner of any age starts at the first unlocked skills.
const { pick, rint, textChoices, q } = require('./helpers');

const _hasEmoji = s => /\p{Extended_Pictographic}/u.test(String(s));
// If only the correct answer carries an emoji, it gives itself away among plain-text
// distractors. Strip it so every choice looks the same.
function _balanceAnswer(a, w) {
  if (_hasEmoji(a) && !w.some(_hasEmoji)) return String(a).replace(/\p{Extended_Pictographic}/gu, '').replace(/\s{2,}/g, ' ').trim();
  return a;
}
function fromBank(bank) {
  return function () {
    const item = pick(bank);
    const a = _balanceAnswer(item.a, item.w);
    return q({
      prompt: item.p,
      choices: textChoices(a, item.w),
      answer: a,
      hint: item.h || '',
      explain: item.e || '',
      voice: item.v || item.p
    });
  };
}

